// Sincronización híbrida en Mobile
override suspend fun updateConfig(token: String, request: Request): Response {
    val tcpResponse = this.device.updateConfig(request) // Intento local
    if (tcpResponse.success) {
        return this.api.updateConfig(token, request.copy(updatedNow = true))
    }
    return this.api.updateConfig(token, request) // Fallback a Cloud
}

// Lógica de procesamiento de credenciales y persistencia
static esp_err_t dataHandler(httpd_req_t *req) {
    char content[200];
    int ret = httpd_req_recv(req, content, sizeof(content) - 1);
    content[ret] = '\0';

    char ssid[32] = {0}, password[64] = {0};
    sscanf(content, "ssid=%31[^&]&password=%63s", ssid, password);

    // Decodificación y persistencia en memoria no volátil (NVS)
    decodeUrlString(ssid);
    decodeUrlString(password);
    device->setWiFiCredentials(ssid, password);

    // Feedback en display y reinicio del hardware
    display->message("Guardado", "correctamente");
    vTaskDelay(4000 / portTICK_PERIOD_MS);
    esp_restart();

    return ESP_OK;
}

